func:
// ===============================================
// Preparar query: Movimientos contables desde 2025-01-01
// Para TODAS las cuentas (sin filtro por CODIGO)
// ===============================================
var now = new Date();
var y = now.getFullYear();
var m = String(now.getMonth() + 1).padStart(2, '0');
var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();
var startDate = '20250101';
var endDate = y + m + String(lastDay).padStart(2, '0');

// Generar UUID de sync
var sync_uuid = (
  Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 6).toUpperCase() +
  Math.random().toString(36).substring(2, 6).toUpperCase()
);

msg.startDate = startDate;
msg.endDate = endDate;
msg.sync_uuid = sync_uuid;

// Query: Movimientos contables desde 2025-01-01 hasta fin del mes actual
// Incluye UNIDAD_NEGOCIO para filtro por empresa en el frontend
// Sin TOP — se necesita el dataset completo para Mayor y Caja
var query = ""
 + "SELECT \n"
 + "    V_EZI_CUENTAS.CODIGO,\n"
 + "    V_EZI_CUENTAS.DESCRIPCION AS CUENTA,\n"
 + "    SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) AS FECHA,\n"
 + "    V_TRCONTABLE_.NUMERODOCUMENTO AS ASIENTO,\n"
 + "    COALESCE(V_EZI_ASIENTOS_DETALLES.DETALLE, V_TRCONTABLE_.DETALLE) AS DESCRIPCION,\n"
 + "    V_TRCONTABLE_.NOMBREDESTINATARIO AS PROVEEDOR,\n"
 + "    ISNULL(SUM(V_VALOR_.IMPORTE), 0) AS DEBE,\n"
 + "    ISNULL(SUM(V_VALOR_1.IMPORTE), 0) AS HABER,\n"
 + "    ISNULL(SUM(V_VALOR_.IMPORTE), 0) - ISNULL(SUM(V_VALOR_1.IMPORTE), 0) AS SALDO,\n"
 + "    ISNULL(V_UNIDADOPERATIVA_.NOMBRE, '') AS UNIDAD_NEGOCIO\n"
 + "FROM V_TRCONTABLE_\n"
 + "INNER JOIN V_ITEMCONTABLE_ ON V_TRCONTABLE_.ITEMSTRANSACCION_ID = V_ITEMCONTABLE_.BO_PLACE_ID\n"
 + "INNER JOIN V_VALOR_ ON V_ITEMCONTABLE_.DEBE_ID = V_VALOR_.ID\n"
 + "INNER JOIN V_VALOR_ AS V_VALOR_1 ON V_ITEMCONTABLE_.HABER_ID = V_VALOR_1.ID\n"
 + "INNER JOIN V_EZI_CUENTAS ON V_ITEMCONTABLE_.REFERENCIA_ID = V_EZI_CUENTAS.ID\n"
 + "LEFT OUTER JOIN V_EZI_ASIENTOS_DETALLES ON V_TRCONTABLE_.ID = V_EZI_ASIENTOS_DETALLES.ID\n"
 + "LEFT OUTER JOIN V_UNIDADOPERATIVA_ ON V_TRCONTABLE_.UNIDADOPERATIVA_ID = V_UNIDADOPERATIVA_.ID\n"
 + "WHERE SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) >= '" + startDate + "'\n"
 + "  AND SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) <= '" + endDate + "'\n"
 + "  AND V_EZI_CUENTAS.CODIGO BETWEEN '0' AND '9'\n"
 + "  AND V_TRCONTABLE_.ESTADO = 'C'\n"
 + "GROUP BY\n"
 + "    V_EZI_CUENTAS.CODIGO,\n"
 + "    V_EZI_CUENTAS.DESCRIPCION,\n"
 + "    V_TRCONTABLE_.FECHAAPLICACION,\n"
 + "    V_TRCONTABLE_.NUMERODOCUMENTO,\n"
 + "    COALESCE(V_EZI_ASIENTOS_DETALLES.DETALLE, V_TRCONTABLE_.DETALLE),\n"
 + "    V_TRCONTABLE_.NOMBREDESTINATARIO,\n"
 + "    V_UNIDADOPERATIVA_.NOMBRE\n"
 + "ORDER BY V_EZI_CUENTAS.CODIGO, FECHA DESC;\n";

msg.payload = query;
node.warn('[Sync-Mov] Preparando sync ' + sync_uuid + ' periodo ' + startDate + '-' + endDate);
return msg;

// ===============================================
// Transformar resultado MSSQL → array 2D para Google Sheets
// 12 columnas (A-L) para pestaña Movimientos
// ===============================================
var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var startDate = msg.startDate || '';
var endDate = msg.endDate || '';
var timestamp = new Date().toISOString();

// Guardar metadata
msg._syncInfo = {
  sync_uuid: sync_uuid,
  periodo: startDate + '-' + endDate,
  timestamp: timestamp
};

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-Mov] Sin movimientos en el periodo. Se omite escritura.');
  msg._syncInfo.empty = true;
  msg.payload = null;
  return msg;
}

// Construir array 2D con 12 columnas (A-L)
// A=CODIGO B=CUENTA C=FECHA D=ASIENTO E=DESCRIPCION
// F=PROVEEDOR G=ITEM H=DEBE I=HABER J=SALDO
// K=SYNC_UUID L=UNIDAD_NEGOCIO
var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  var codigo = (r.CODIGO || '').toString().trim();
  var debe = parseFloat(r.DEBE) || 0;
  var haber = parseFloat(r.HABER) || 0;
  var saldo = parseFloat(r.SALDO) || (debe - haber);
  var unidadNegocio = (r.UNIDAD_NEGOCIO || '').toString().trim();

  data.push([
    codigo,                            // A: CODIGO
    (r.CUENTA || '').toString(),       // B: CUENTA
    (r.FECHA || '').toString(),        // C: FECHA
    (r.ASIENTO || '').toString(),      // D: ASIENTO
    (r.DESCRIPCION || '').toString(),  // E: DESCRIPCION
    (r.PROVEEDOR || '').toString(),    // F: PROVEEDOR
    '',                                // G: ITEM (placeholder)
    debe,                              // H: DEBE
    haber,                             // I: HABER
    saldo,                             // J: SALDO
    sync_uuid,                         // K: SYNC_UUID
    unidadNegocio                      // L: UNIDAD_NEGOCIO
  ]);
}

msg._sheetData = data;
msg.payload = data;
msg._syncInfo.rowCount = data.length;
node.warn('[Sync-Mov] ' + data.length + ' movimientos (12 cols A-L). UUID=' + sync_uuid);
return msg;

// El GSheet Clear sobreescribe msg.payload con la respuesta de la API
// Restaurar el array 2D desde _sheetData para que el Append funcione
if (msg._sheetData) {
  msg.payload = msg._sheetData;
}
return msg;

// ===============================================
// Procesar resultado del sync de Movimientos
// ===============================================
var info = msg._syncInfo || {};

if (info.empty) {
  node.warn('[Sync-Mov] Sync omitido: sin movimientos en el periodo ' + (info.periodo || '?'));
  return msg;
}

if (msg.error) {
  node.error('[Sync-Mov] ERROR al escribir en Google Sheets: ' + msg.error);
  return msg;
}

var updatedRange = '';
if (msg.payload && msg.payload.updates) {
  updatedRange = msg.payload.updates.updatedRange || '';
}

node.warn('[Sync-Mov] ✅ Sync de movimientos exitoso');
node.warn('[Sync-Mov]    UUID: ' + (info.sync_uuid || '?'));
node.warn('[Sync-Mov]    Periodo: ' + (info.periodo || '?'));
node.warn('[Sync-Mov]    Filas: ' + (info.rowCount || 0));
node.warn('[Sync-Mov]    Rango: ' + updatedRange);
node.warn('[Sync-Mov]    Columnas: A-L (12 cols) → pestaña Movimientos');

msg._syncResult = {
  success: true,
  uuid: info.sync_uuid,
  periodo: info.periodo,
  rows: info.rowCount,
  range: updatedRange,
  timestamp: info.timestamp
};

return msg;
